// Helper functions
export function getIndustriesByCategory(category: IndustryCategory): Industry[] {
  return industriesDatabase.filter(industry => industry.category === category)
}

export function searchIndustries(query: string): Industry[] {
  const lowerQuery = query.toLowerCase()
  return industriesDatabase.filter(industry => 
    industry.name.toLowerCase().includes(lowerQuery) ||
    industry.keywords.some(keyword => keyword.toLowerCase().includes(lowerQuery))
  )
}

export function getIndustryCategories(): IndustryCategory[] {
  return Array.from(new Set(industriesDatabase.map(i => i.category)))
}
